queries.sparql:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?title ?genre WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:playId ?cg . ?child a :Play ; p:id ?cg . ?l p:theatreId ?pg . ?parent a :Theatre ; p:id ?pg . } GROUP BY ?child }
  ?child p:title ?title .
  ?child p:genre ?genre .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Theatre } }
  FILTER(?nf = ?total)
}

